{{#if:<!--test first character for lower-case letter-->{{#invoke:string|find|{{Str left|{{{1|}}}|1}}|[a-z]|plain=false}}
|<!-- first character is a lower case letter; test against whitelist
-->{{#if:{{#invoke:String2|matchAny|c.|none|iMac|iTunes|source={{First word|{{{1|}}}}}}}
|<!-- short description starts with an allowed lower-case word; whitelist matched; do nothing -->
|<!-- apply category for lower-case short descriptions -->[[Category:Pages with lower-case short description]]
<!-- end whitelist test -->}}
|<!-- short description does not start with lower-case letter; do nothing; -->
<!-- end lower-case test -->}}<noinclude>
{{documentation}}
</noinclude>

{{#if:<!--test first character for lower-case letter-->{{#invoke:string|find|{{Str left|{{{1|}}}|1}}|[a-z]|plain=false}}
